1	import { describe, it, before, after } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { createServer } from 'node:http';
4	import WebSocket from 'ws';
5	import { initWs, broadcast, closeWs } from '../ws/broadcaster.js';
6	
7	// ── Helpers ───────────────────────────────────────────────────────────────────
8	
9	function startWsServer(opts = {}) {
10	  return new Promise((resolve) => {
11	    const httpServer = createServer();
12	    initWs(httpServer, opts);
13	    httpServer.listen(0, () => {
14	      const { port } = httpServer.address();
15	      resolve({ httpServer, wsUrl: `ws://localhost:${port}` });
16	    });
17	  });
18	}
19	
20	async function stopWsServer(httpServer) {
21	  await closeWs();
