      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: 'X' }),
    });
    await new Promise((resolve) => setTimeout(resolve, 100));
    assert.strictEqual(unexpected.length, 0);
    await closeWsClient(ws);
