```javascript
import { Router } from 'express';
import { createCard, updateCard, deleteCard, moveCard, NotFoundError } from '../db/queries.js';
import { broadcast } from '../ws/broadcaster.js';

const router = Router();

// POST /api/cards — create a card
router.post('/cards', (req, res, next) => {
  const { title, assignee, column, description } = req.body ?? {};
  if (!title) {
    return res.status(400).json({ error: 'title is required' });
  }
  try {
    const card = createCard({ title, assignee, column, description });
    try { broadcast('card:created', card); } catch { /* isolate broadcast errors */ }
    return res.status(201).json(card);
  } catch (err) {
    next(err);
  }
});

// PATCH /api/cards/:id — update a card
router.patch('/cards/:id', (req, res, next) => {
  try {
    const card = updateCard(req.params.id, req.body ?? {});
    try { broadcast('card:updated', card); } catch { /* isolate broadcast errors */ }
    return res.status(200).json(card);
  } catch (err) {
    if (err instanceof NotFoundError) {
      return res.status(404).json({ error: err.message });
    }
    next(err);
  }
});

// DELETE /api/cards/:id — delete a card
router.delete('/cards/:id', (req, res, next) => {
  try {
    deleteCard(req.params.id);
    try { broadcast('card:deleted', { id: req.params.id }); } catch { /* isolate */ }
    return res.status(204).send();
  } catch (err) {
    if (err instanceof NotFoundError) {
      return res.status(404).json({ error: err.message });
    }
    next(err);
  }
});

// PATCH /api/cards/:id/move — move a card
router.patch('/cards/:id/move', (req, res, next) => {
  const { column, position } = req.body ?? {};
  if (!column || position === undefined || position === null) {
    return res.status(400).json({ error: 'column and position are required' });
  }
  try {
    const card = moveCard(req.params.id, column, position);
    try { broadcast('card:moved', card); } catch { /* isolate */ }
    return res.status(200).json(card);
  } catch (err) {
    if (err instanceof NotFoundError) {
      return res.status(404).json({ error: err.message });
    }
    next(err);
  }
});

export default router;
```

**Design decisions:**

- The inner `try { broadcast(...) } catch {}` pattern means a broadcast failure (e.g., a broken WebSocket send) never reaches Express's error handler. The HTTP response has already been sent or is about to be sent. Note: `broadcast()` itself already has per-client `try-catch` internally, but we wrap the entire call defensively in case of other failures (e.g., `JSON.stringify` throwing on a circular reference in a payload).
- `position === undefined || position === null` check handles: missing key (`undefined`), explicit `null`, but allows `0` and negative numbers (which `moveCard` handles as "move to first position").
- Route ordering: `/cards/:id/move` must be registered before it could conflict with `/cards/:id`. In Express, `PATCH /cards/:id` and `PATCH /cards/:id/move` are distinct because `/move` is a literal path segment — Express will not match `/cards/some-id/move` to `PATCH /cards/:id`.

