467	const CARD_UPDATE_ALLOWED = ['title', 'assignee', 'column', 'description', 'position'];
468	router.patch('/cards/:id', (req, res, next) => {
469	  const updateData = req.body ?? {};
470	  try {
471	    const card = updateCard(req.params.id, updateData);
472	    // Only broadcast when at least one recognized field was in the request body,
473	    // meaning updateCard actually performed a DB write. An empty or unrecognized-only
474	    // body causes updateCard to return the card unchanged (no DB write), so no broadcast.
475	    if (Object.keys(updateData).some(k => CARD_UPDATE_ALLOWED.includes(k))) {
476	      try { broadcast('card:updated', card); } catch { /* isolate broadcast errors */ }
477	    }
478	    return res.status(200).json(card);
