491	    try { broadcast('card:deleted', { id: req.params.id }); } catch { /* isolate */ }
492	    return res.status(204).send();
493	  } catch (err) {
494	    if (err instanceof NotFoundError) {
495	      return res.status(404).json({ error: err.message });
496	    }
497	    next(err);
498	  }
499	});
